// 假定获取输入的query对象
let query = $input.all()[0].json.query;

// 解析Country和firmware_type字段
let countries = query.Country !== "[]" ? JSON.parse(query.Country) : [];
let firmwareTypes = query.firmware_type !== "[]" ? JSON.parse(query.firmware_type) : [];

// 把"Overseas"替换成"EU"和"US"
countries = countries.flatMap(country => country === "Overseas" ? ["EU", "US"] : country);

// 初始化SQL语句
let sql = `
  SELECT
    (SELECT COUNT(*) FROM public.activation_records WHERE `;

// 条件列表
let conditions = [];

// 根据是否有数据添加条件
if (countries.length > 0) {
    conditions.push(`country_code IN ('${countries.join("', '")}')`);
}

if (firmwareTypes.length > 0) {
    conditions.push(`firmware_type IN ('${firmwareTypes.join("', '")}')`);
}

if (query.ActiveDate_Start !== "1970-01-01" || query.ActiveDate_End !== "1970-01-01") {
    conditions.push(`to_timestamp(activatetime::bigint) >= '${query.ActiveDate_Start}'::timestamp`);
    conditions.push(`to_timestamp(activatetime::bigint) <= '${query.ActiveDate_End}'::timestamp + interval '1 day' - interval '1 second'`);
}

// 如果有条件，添加到SQL语句中
if (conditions.length > 0) {
    sql += conditions.join(" AND ") + `) AS total_count,`;
} else {
    sql += `true) AS total_count,`;
}

sql += `
    A.defective_duration_days
  FROM
    public.defective_records AS A
  INNER JOIN
    public.activation_records AS B
  ON
    A.active_id = B.id
`;

// 清空条件列表
conditions = [];

// 重新添加条件列表
if (countries.length > 0) {
    conditions.push(`B.country_code IN ('${countries.join("', '")}')`);
}

if (firmwareTypes.length > 0) {
    conditions.push(`B.firmware_type IN ('${firmwareTypes.join("', '")}')`);
}

if (query.ActiveDate_Start !== "1970-01-01" || query.ActiveDate_End !== "1970-01-01") {
    conditions.push(`to_timestamp(B.activatetime::bigint) >= '${query.ActiveDate_Start}'::timestamp`);
    conditions.push(`to_timestamp(B.activatetime::bigint) <= '${query.ActiveDate_End}'::timestamp + interval '1 day' - interval '1 second'`);
}

// 如果有条件，添加到SQL语句中
if (conditions.length > 0) {
    sql += " WHERE " + conditions.join(" AND ");
}

sql += `
GROUP BY
  A.defective_duration_days;
`;

// 输出结果
return {sql: sql};

// 输入数据
const input = $input.all();

// 检查输入数据是否为空
if (input.length === 0) {
    return [];
}

// 初始化数据结构
let resultData = {
  total_count: null,
  count: []
};
let categoriesData = [];
let categoryMap = {};
let totalCountSet = new Set(); 

// 1. 遍历输入数据进行分类统计
input.forEach(item => {
  const totalCount = item.json.total_count;
  const defectiveDurationDays = parseFloat(item.json.defective_duration_days);

  let category;

  // 确定分类
  if (defectiveDurationDays < 0) {
    category = "异常数据";
  } else if (defectiveDurationDays > 24 * 30) {
    category = "超过2年";
  } else {
    const monthCategoryNumber = Math.floor(defectiveDurationDays / 30) + 1;
    category = `${monthCategoryNumber}个月`;
  }

  // 确保分类只出现一次，每个分类对应一个位置
  if (!(category in categoryMap)) {
    categoryMap[category] = categoriesData.length; // 保存分类索引
    categoriesData.push(category);
    resultData.count.push(0);
  }

  // 增加对应分类的计数
  const categoryIndex = categoryMap[category];
  resultData.count[categoryIndex]++;

  // 收集所有的total_count确保它们都是一致的
  totalCountSet.add(totalCount); 
});

// 2. ============== 新增逻辑：计算累积总数 ==============
let accumulatedList = [];
let runningTotal = 0;

resultData.count.forEach(num => {
    runningTotal += num; // 累加当前数量
    accumulatedList.push(runningTotal); // 放入新数组
});

// 将累积数组放入 resultData
resultData.accumulated_count = accumulatedList;
// ======================================================

// 检查 totalCountSet是否只包含一个唯一的值
if (totalCountSet.size === 1) {
  resultData.total_count = totalCountSet.values().next().value;
} else {
  resultData.total_count = "数据不一致";
}

// 构建最终输出
const output = [
  {
    result: resultData,
    categoriesData: categoriesData
  }
];

return output;
